sql:
SELECT movie_id, SUM(lifetime_earnings) AS total_lifetime_earnings, SUM(screens) AS total_screens
FROM box_office_performance
GROUP BY movie_id;

SELECT movie_id, sentiment_score
FROM audience_engagement
WHERE sentiment_score > 0.7;

SELECT SUM(ual.duration) AS total_duration_accessed
FROM user_access_logs ual
WHERE ual.movie_id = 1 AND ual.access_type = 'view';

SELECT movie_id, lifetime_earnings
FROM box_office_performance
ORDER BY lifetime_earnings DESC;

SELECT AVG(conversion_rate) AS average_conversion_rate
FROM marketing_campaigns
WHERE target_audience = '25-45';

external_knowledge:
- 'blockbusters' refers to movies with lifetime earnings of over $1 million and an average rating greater than 6; 
- 'made a fortune' refers to lifetime earnings of over $1 million; 
- 'impressed audiences' refers to an average rating greater than 6.
